#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a Trie node
typedef struct Node {
    struct Node* links[26];
    int cntEndWith;
    int cntPrefix;
} Node;

// Function to create a new Trie node
Node* createNode() {
    Node* node = (Node*) malloc(sizeof(Node));
    for (int i = 0; i < 26; i++) {
        node->links[i] = NULL;
    }
    node->cntEndWith = 0;
    node->cntPrefix = 0;
    return node;
}

// Function to insert a word into the Trie
void insert(Node* root, char* word) {
    Node* node = root;
    for (int i = 0; i < strlen(word); i++) {
        if (node->links[word[i] - 'a'] == NULL) {
            node->links[word[i] - 'a'] = createNode();
        }
        node = node->links[word[i] - 'a'];
        node->cntPrefix++;
    }
    node->cntEndWith++;
}

// Function to count the number of words equal to a given word
int countWordsEqualTo(Node* root, char* word) {
    Node* node = root;
    for (int i = 0; i < strlen(word); i++) {
        if (node->links[word[i] - 'a'] == NULL) {
            return 0;
        }
        node = node->links[word[i] - 'a'];
    }
    return node->cntEndWith;
}

// Function to count the number of words starting with a given prefix
int countWordsStartingWith(Node* root, char* word) {
    Node* node = root;
    for (int i = 0; i < strlen(word); i++) {
        if (node->links[word[i] - 'a'] == NULL) {
            return 0;
        }
        node = node->links[word[i] - 'a'];
    }
    return node->cntPrefix;
}

// Function to erase a word from the Trie
void erase(Node* root, char* word) {
    Node* node = root;
    for (int i = 0; i < strlen(word); i++) {
        node = node->links[word[i] - 'a'];
        node->cntPrefix--;
    }
    node->cntEndWith--;
}

int main() {
    Node* root = createNode();
    // Perform operations on the Trie
    insert(root, "apple");
    insert(root, "app");
    printf("Count Words Equal to 'apple': %d\n", countWordsEqualTo(root, "apple"));
    printf("Count Words Starting With 'app': %d\n", countWordsStartingWith(root, "app"));
    erase(root, "apple");
    printf("Count Words Equal to 'apple': %d\n", countWordsEqualTo(root, "apple"));
    return 0;
}

